{
  "domain_analysis": {
    "business_context": "Leave management module within an HR software system. Governs the lifecycle of employee leave: accrual, requesting, approval, consumption, carryover, and forfeiture. Must enforce labor-policy compliance while supporting both planned and unplanned (medical) absence workflows.",
    "bounded_context": "Leave Management",
    "ubiquitous_language": [
      { "term": "Leave Balance", "definition": "The current number of accrued, unconsumed leave days available to an employee. Must never be negative." },
      { "term": "Accrual", "definition": "The process by which an employee earns 1.5 leave days for each calendar month worked under an active contract." },
      { "term": "Leave Request", "definition": "A formal submission by an employee to consume accrued leave for a specified date range. Has a lifecycle: Pending → Approved/Rejected." },
      { "term": "Medical Leave", "definition": "A special leave type that may be submitted retroactively (after the absence) provided a doctor's note is attached within 5 calendar days of the absence." },
      { "term": "Working Days", "definition": "Business days excluding weekends and company-recognized holidays; used to calculate the advance-notice requirement." },
      { "term": "Doctor's Note", "definition": "A medical certificate from a licensed practitioner that must accompany retroactive medical leave requests." },
      { "term": "Carryover", "definition": "The transfer of unused leave balance from one calendar year to the next, capped at 10 days. Any excess is forfeited." },
      { "term": "Forfeiture", "definition": "The permanent loss of accrued leave days exceeding the 10-day carryover cap at the calendar year boundary." },
      { "term": "Contract End Date", "definition": "The termination date of an employee's current employment contract. Leave requests must not extend beyond this date." },
      { "term": "Advance Notice Period", "definition": "A minimum of 3 working days between the date a non-medical leave request is submitted and the first day of requested leave." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Employees accrue 1.5 leave days per calendar month worked under an active contract.",
      "invariant": false,
      "invariant_justification": "The accrual rate of 1.5 days/month is a policy parameter that HR leadership could change (e.g., to 2.0 days for senior employees). The mechanism of monthly accrual is stable, but the rate is a business policy.",
      "testable_assertion": "After N complete months of employment, an employee's total accrued leave equals N × 1.5 days (before any consumption)."
    },
    {
      "id": "BR-2",
      "rule": "An employee's leave balance must never go below zero. Leave cannot be taken before it is accrued.",
      "invariant": true,
      "invariant_justification": "A negative leave balance represents a physically impossible state — consuming something that does not exist. This is a data integrity constraint; if violated, downstream payroll and compliance calculations are corrupt.",
      "testable_assertion": "For any employee at any point in time: leave_balance >= 0. Any leave request where requested_days > current_balance must be rejected by the system."
    },
    {
      "id": "BR-3",
      "rule": "Non-medical leave requests must be submitted at least 3 working days before the first day of requested leave.",
      "invariant": false,
      "invariant_justification": "The 3-working-day advance notice is a policy threshold that management could adjust (e.g., reduce to 2 days or increase to 5). It is not a state-integrity constraint.",
      "testable_assertion": "Given a non-medical leave request submitted on date S for leave starting on date L, the number of working days between S (exclusive) and L (inclusive) must be >= 3, otherwise the system rejects the request."
    },
    {
      "id": "BR-4",
      "rule": "Medical leave can be submitted retroactively within 5 calendar days of the absence, provided a doctor's note is attached.",
      "invariant": false,
      "invariant_justification": "The 5-day retroactive window and the doctor's note requirement are policy decisions, not state-integrity constraints. A VP could change the window to 7 days or accept other forms of evidence.",
      "testable_assertion": "A medical leave request for absence on date A, submitted on date S, is valid only if S <= A + 5 calendar days AND a doctor's note document is attached. If either condition fails, the request is rejected."
    },
    {
      "id": "BR-5",
      "rule": "Only a manager can approve or reject a leave request. Approval consumes leave balance; rejection does not.",
      "invariant": true,
      "invariant_justification": "This encodes authorization integrity (only managers decide) and state consistency (rejected leave must not decrement balance). If a rejection consumed balance, the system state would be corrupt — leave consumed with no actual absence.",
      "testable_assertion": "When a leave request is rejected, the employee's leave balance before and after the rejection must be identical. When approved, balance decreases by exactly the number of leave days in the request."
    },
    {
      "id": "BR-6",
      "rule": "A leave request must not span beyond the employee's contract end date.",
      "invariant": true,
      "invariant_justification": "An employee cannot be on leave when they are no longer employed. Allowing leave past contract end would create a legally and logically invalid state — consuming company resources for a non-employee.",
      "testable_assertion": "For any leave request, the last day of requested leave must be <= the employee's contract end date. Requests violating this are rejected at submission time."
    },
    {
      "id": "BR-7",
      "rule": "At calendar year-end, unused leave above 10 days is forfeited. A maximum of 10 days carries over to January 1 of the next year.",
      "invariant": false,
      "invariant_justification": "The 10-day carryover cap is a policy threshold that could be changed by HR leadership (e.g., increased to 15 during a pandemic). The mechanism of year-end processing is stable, but the cap value is policy.",
      "testable_assertion": "On January 1, an employee's carried-over balance equals min(previous_year_ending_balance, 10). Any excess is recorded as forfeited and is irrecoverable."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An employee has worked 4 complete months with no leave taken",
      "when": "The system calculates their leave balance",
      "then": "The balance is exactly 6.0 days (4 × 1.5)"
    },
    {
      "id": "AC-2",
      "given": "An employee has a leave balance of 2.0 days",
      "when": "They submit a non-medical leave request for 3.0 days",
      "then": "The system rejects the request with an insufficient-balance error and the balance remains 2.0 days"
    },
    {
      "id": "AC-3",
      "given": "An employee submits a non-medical leave request on a Monday",
      "when": "The requested leave start date is Thursday of the same week (3 working days: Tue, Wed, Thu)",
      "then": "The request is accepted for manager review (advance notice satisfied)"
    },
    {
      "id": "AC-4",
      "given": "An employee submits a non-medical leave request on a Wednesday",
      "when": "The requested leave start date is Friday of the same week (2 working days: Thu, Fri)",
      "then": "The system rejects the request for insufficient advance notice"
    },
    {
      "id": "AC-5",
      "given": "An employee was absent on March 10 due to illness",
      "when": "They submit a medical leave request on March 14 with a valid doctor's note attached",
      "then": "The request is accepted for manager review (within the 5-day retroactive window)"
    },
    {
      "id": "AC-6",
      "given": "An employee was absent on March 10 due to illness",
      "when": "They submit a medical leave request on March 16 (6 days later) with a doctor's note",
      "then": "The system rejects the request because it exceeds the 5-day retroactive submission window"
    },
    {
      "id": "AC-7",
      "given": "An employee submits a medical leave request retroactively within 5 days",
      "when": "No doctor's note is attached",
      "then": "The system rejects the request and indicates that a doctor's note is required"
    },
    {
      "id": "AC-8",
      "given": "A manager reviews a pending leave request and rejects it",
      "when": "The rejection is recorded",
      "then": "The employee's leave balance is unchanged and the request status is 'Rejected'"
    },
    {
      "id": "AC-9",
      "given": "A manager reviews a pending leave request for 3 days and approves it",
      "when": "The approval is recorded",
      "then": "The employee's leave balance decreases by exactly 3.0 days and the request status is 'Approved'"
    },
    {
      "id": "AC-10",
      "given": "An employee's contract ends on June 30",
      "when": "They submit a leave request for June 28 to July 2",
      "then": "The system rejects the request because it spans beyond the contract end date"
    },
    {
      "id": "AC-11",
      "given": "An employee has 14 unused leave days on December 31",
      "when": "The year-end carryover process runs",
      "then": "The employee's balance on January 1 is 10 days and 4 days are recorded as forfeited"
    },
    {
      "id": "AC-12",
      "given": "An employee has 8 unused leave days on December 31",
      "when": "The year-end carryover process runs",
      "then": "The employee's balance on January 1 is 8 days and 0 days are forfeited"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Employee submits non-medical leave where the advance notice period spans a public holiday (e.g., submit Monday, leave starts Thursday, but Wednesday is a holiday — only 2 working days)",
      "expected_behavior": "The system must count only working days (excluding holidays) when evaluating the 3-day advance notice. This request should be rejected."
    },
    {
      "scenario": "Employee submits a medical leave request on exactly the 5th calendar day after the absence",
      "expected_behavior": "The request is accepted — the 5-day window is inclusive of day 5. (Spec says 'within 5 days,' which by convention includes the boundary.)"
    },
    {
      "scenario": "Partial month worked at start or end of employment — does the employee accrue a pro-rated 1.5 days or nothing?",
      "expected_behavior": "The spec says 'per month worked' but does not define partial months. This needs clarification — see escalations. Likely options: pro-rata, full accrual if >15 days worked, or no accrual for partial months."
    },
    {
      "scenario": "Leave request is approved but then the employee's contract end date is subsequently shortened (e.g., early termination) to fall within the approved leave period",
      "expected_behavior": "Previously approved leave extending beyond the new contract end date must be cancelled and the consumed balance restored. The invariant that leave cannot extend past contract end must hold even retroactively."
    },
    {
      "scenario": "Employee submits a leave request consuming their exact remaining balance, then a carryover forfeiture runs before the leave is approved",
      "expected_behavior": "The system must re-validate balance sufficiency at approval time, not just submission time. If forfeiture reduced the balance, approval must fail."
    },
    {
      "scenario": "Manager tries to approve a leave request but the employee's balance has changed since submission (e.g., another request was approved in between)",
      "expected_behavior": "Balance sufficiency must be re-validated at the moment of approval. If balance is now insufficient, approval must be blocked despite the request being valid at submission time."
    },
    {
      "scenario": "Leave request starts before and ends after a calendar year boundary (e.g., Dec 28 to Jan 3)",
      "expected_behavior": "The spec does not address this. The system needs a rule for whether leave days are allocated to the year they fall in, and how carryover interacts with in-flight leave spanning the boundary. See escalations."
    },
    {
      "scenario": "Employee has zero balance and submits a retroactive medical leave request with a doctor's note",
      "expected_behavior": "Rejected — BR-2 (non-negative balance) is an invariant. Medical leave exempts the advance-notice rule, not the balance rule. The employee cannot go negative regardless of leave type."
    }
  ],

  "business_impact": {
    "financial": "Accurate accrual and forfeiture logic directly impacts leave liability on the balance sheet. Errors in carryover calculation can result in over- or under-provisioning of leave liabilities. Negative balance bugs effectively grant unauthorized paid leave — a direct payroll cost leak.",
    "operational": "The 3-day advance notice rule enables workforce planning and shift coverage. Medical leave retroactivity balances employee wellbeing with operational tracking. Year-end forfeiture incentivizes leave utilization, reducing end-of-year leave pileups that disrupt operations.",
    "user": "Employees need transparent, real-time visibility into their accrued balance and clear feedback when requests are rejected (with specific reasons). Managers need a streamlined approval workflow. Confusing rejection messages or incorrect balances erode trust in the HR system.",
    "risk": "Non-negative balance invariant is the highest-risk item — if violated, it creates legal exposure (unpaid leave disputes), payroll errors, and audit findings. Contract-end-date validation failure could result in paying someone who is no longer employed. Retroactive medical leave without proper doctor's note validation creates fraud exposure.",
    "stakeholders_affected": [
      { "group": "Employees", "impact": "Direct users — submit requests, track balances, receive approvals/rejections. Incorrect balances or unclear rejection reasons cause frustration and HR support tickets." },
      { "group": "Managers", "impact": "Approve/reject workflow — need clear visibility into team leave schedules and remaining balances to make informed decisions." },
      { "group": "HR/People Operations", "impact": "Administers accrual rates, carryover policies, and handles disputes. Must audit forfeiture events and ensure compliance with labor regulations." },
      { "group": "Payroll", "impact": "Downstream consumer of approved leave data. Incorrect leave balances cascade into incorrect salary calculations." },
      { "group": "Finance/Accounting", "impact": "Leave liability must be accurately reported. Carryover and forfeiture events affect year-end financial statements." },
      { "group": "Legal/Compliance", "impact": "Labor law compliance varies by jurisdiction. The forfeiture rule and retroactive medical leave window may be subject to local employment law constraints." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The spec is well-structured for core rules but leaves several operationally critical details undefined: partial-month accrual, cross-year leave requests, half-day leave granularity, the definition of 'working days' (company-specific holidays), and whether balance is checked at submission or approval time. These gaps could lead to materially different implementations. Additionally, the forfeiture and medical leave rules may conflict with local labor laws that the spec does not reference.",
    "high_confidence_areas": [
      "Non-negative balance invariant (BR-2) — unambiguous and clearly stated",
      "Rejection does not consume balance (BR-5) — explicit and testable",
      "Contract end date boundary (BR-6) — clear constraint",
      "Carryover cap at 10 days with forfeiture (BR-7) — well-defined"
    ],
    "low_confidence_areas": [
      "Partial-month accrual — spec says 'per month worked' without defining partial months",
      "Cross-year-boundary leave requests — no rule for how leave spanning Dec/Jan interacts with forfeiture",
      "Working days definition — company holiday calendar not specified, critical for advance notice calculation",
      "Balance validation timing — at submission, at approval, or both?",
      "Whether medical leave balance exemption exists — spec is silent on zero-balance medical leave"
    ],
    "assumptions": [
      "'Within 5 days' for medical leave means 5 calendar days, inclusive of the boundary day",
      "Balance must be validated at both submission and approval time to prevent race conditions",
      "Medical leave exempts the advance-notice rule only — not the balance rule",
      "Accrual runs once per calendar month on a fixed schedule (e.g., 1st of month for prior month)",
      "'Working days' excludes weekends (Saturday/Sunday) and company-recognized public holidays"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec states accrual is '1.5 days per month worked' but does not define how partial months are handled (first month of employment, last month before termination, or unpaid leave mid-month). This materially affects balance calculations for every employee.",
      "affected_stakeholders": ["Employees", "HR/People Operations", "Payroll"],
      "options": [
        "Pro-rata accrual based on days worked in the month",
        "Full 1.5-day accrual if employee works more than 15 calendar days in the month",
        "No accrual for any partial month"
      ],
      "recommendation": "Pro-rata accrual (option A) is the most employee-friendly and legally defensible approach, but the business must confirm."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not address leave requests that span a calendar year boundary (e.g., Dec 28 – Jan 3). It is unclear whether the days should be split across years for forfeiture calculation, or treated as belonging to the year the leave starts.",
      "affected_stakeholders": ["Employees", "Finance/Accounting", "HR/People Operations"],
      "options": [
        "Each leave day is attributed to the calendar year it falls in — forfeiture calculated after splitting",
        "Entire leave block attributed to the year the leave starts",
        "System blocks cross-year leave requests and requires two separate requests"
      ],
      "recommendation": "Option A (split by calendar day) is the most accurate for financial reporting, but option C (block cross-year requests) is simplest to implement and avoids ambiguity."
    },
    {
      "type": "ambiguity",
      "description": "Balance validation timing is not specified. If balance is only checked at submission time, a race condition exists where two overlapping requests could both pass validation but together exceed the available balance.",
      "affected_stakeholders": ["Employees", "Payroll", "HR/People Operations"],
      "options": [
        "Validate balance at submission only (simpler but allows over-consumption via concurrent requests)",
        "Validate balance at both submission and approval time (safe but may confuse employees whose valid request later fails)",
        "Reserve (hold) balance at submission, release on rejection (most robust but adds complexity)"
      ],
      "recommendation": "Option C (reservation model) is the gold standard for preventing over-consumption. At minimum, option B must be implemented to protect the non-negative balance invariant."
    },
    {
      "type": "missing_context",
      "description": "The definition of 'working days' depends on a company holiday calendar which is not specified. The advance notice rule (BR-3) cannot be correctly implemented without this.",
      "affected_stakeholders": ["Employees", "Managers"],
      "options": [
        "Working days = Monday–Friday excluding a configurable public holiday list",
        "Working days = Monday–Friday only (ignore holidays)",
        "Working days defined per employee based on their work schedule"
      ],
      "recommendation": "Option A is standard for most HR systems. The system must accept a configurable holiday calendar per legal entity or location."
    }
  ],

  "rejection_reasons": []
}

